	var commits []models.CommitChanges
	err := json.Unmarshal([]byte(jsonData), &commits)
	if err != nil {
		log.Fatal("Error to read JSON: ", err)
	}

	file, err := os.Create("result_commits.csv")
	if err != nil {
		log.Fatal("Error to create file: ", err)
	}
	defer file.Close()

	writer := csv.NewWriter(file)
	defer writer.Flush()

	writer.Write([]string{"id", "sha", "changes"})

	for i, commit := range commits {
		linha := []string{
			fmt.Sprintf("%d", i+1),            // id (1, 2, 3...)
			commit.SHA,                        // sha
			fmt.Sprintf("%d", commit.Changes), // changes
		}
		writer.Write(linha)
	}

	fmt.Println("Susses!")
